#!/usr/bin/env sh
# Простейший POSIX-совместимый скрипт
# Останавливаемся при любой ошибке
set -e

VERSION="$1"    # Например, "1.4.0-beta.26"
LAST_TAG="$2"   # Например, "v1.4.0-beta.25"

echo "=== Release $VERSION was successful ==="
echo "LAST_TAG = $LAST_TAG"

# 1. Сохраняем коммиты за период между предыдущим релизом и текущим HEAD
git log "$LAST_TAG"..HEAD --pretty=format:"%s" > commits.txt

# 2. Находим все задачи вида DSB-3166 (DSB-[число]) и складываем их через запятую
tasks=$(grep -oE "DSB-[0-9]+" commits.txt | sort | uniq | paste -sd "," -)

echo "=== Found tasks: $tasks ==="

if [ -z "$tasks" ]; then
  echo "No DSB-xxxx tasks found for this release."
fi

echo "Creating version v$VERSION in Jira..."

# 3. Создаем версию в Jira и получаем её ID, используя 'jq'
versionId=$(
  curl -s -X POST \
    -H "Authorization: Bearer ${JIRA_TOKEN}" \
    -H "Content-Type: application/json" \
    -d "{
      \"project\": \"DSB\",
      \"name\": \"v$VERSION\",
      \"description\": \"Release v$VERSION | Tasks: $tasks\",
      \"released\": true,
      \"releaseDate\": \"$(date +%Y-%m-%d)\"
    }" \
    "https://btask.beeline.ru/rest/api/2/version" \
  | jq -r '.id'
)

echo "Created Jira version with id=$versionId"

# 4. Если есть задачи, то проставляем им fixVersion (по имени) и переводим в Done
if [ -n "$tasks" ]; then
  # Разбиваем строку tasks="DSB-3166,DSB-3167" на отдельные элементы
  set -- $(echo "$tasks" | tr ',' ' ')
  # Теперь "$@" содержит список: DSB-3166 DSB-3167 ...
  for issueKey in "$@"; do
    echo "Updating task: $issueKey"

    # 4A) Полностью заменяем fixVersion вместо добавления
    curl -s -X PUT \
      -H "Authorization: Bearer ${JIRA_TOKEN}" \
      -H "Content-Type: application/json" \
      -d "{
        \"fields\": {
          \"fixVersions\": [
            { \"name\": \"v$VERSION\" }
          ]
        }
      }" \
      "https://btask.beeline.ru/rest/api/2/issue/$issueKey"

    echo "Task $issueKey: fixVersion set to name=v$VERSION (replaced any existing versions)"

    # # 4B) Переводим задачу в Done (пример ID=151)
    # curl -s -X POST \
    #   -H "Authorization: Bearer ${JIRA_TOKEN}" \
    #   -H "Content-Type: application/json" \
    #   -d "{
    #     \"transition\": { \"id\": 151 }
    #   }" \
    #   "https://btask.beeline.ru/rest/api/2/issue/$issueKey/transitions"

    # echo "Task $issueKey: moved to Done"
  done
fi

echo "All Jira updates done!"
